import{l,a as r,c as o,a6 as n}from"./chunks/framework.C0d1FTMf.js";const d=JSON.parse('{"title":"表达框架","description":"","frontmatter":{},"headers":[],"relativePath":"interview/talk.md","filePath":"interview/talk.md"}'),i={name:"interview/talk.md"};function s(g,t,a,e,u,p){return r(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="表达框架" tabindex="-1">表达框架 <a class="header-anchor" href="#表达框架" aria-label="Permalink to &quot;表达框架&quot;">​</a></h1><p>以下是为你整理的7种经典思维模型/表达框架，每种包含<strong>3个不同场景</strong>的实战使用示例：</p><h3 id="_1-prep-即兴发言" tabindex="-1">1. PREP（即兴发言） <a class="header-anchor" href="#_1-prep-即兴发言" aria-label="Permalink to &quot;1. PREP（即兴发言）&quot;">​</a></h3><p><strong>结构：观点 (Point) -&gt; 理由 (Reason) -&gt; 案例 (Example) -&gt; 重申 (Point)</strong></p><ul><li><p><strong>示例1：职场汇报（关于是否要加班）</strong></p><ul><li><strong>观点：</strong> 我认为我们应该停止无效的“形式主义加班”。</li><li><strong>理由：</strong> 因为长时间的工作会显著降低第二天的专注力，反而增加了代码的出错率。</li><li><strong>案例：</strong> 上周三我们加班到凌晨两点，结果周四上午就因为精神状态不佳漏掉了一个关键校验，导致回滚修复花了更多时间。</li><li><strong>重申：</strong> 所以，提高效率而不是堆砌时长，才是我们团队应该追求的目标。</li></ul></li><li><p><strong>示例2：面试回答（你为什么适合这个岗位？）</strong></p><ul><li><strong>观点：</strong> 我认为我是这个岗位的最佳人选，因为我具备极强的用户增长经验。</li><li><strong>理由：</strong> 我在上一份工作中积累了完整的裂变营销方法论，能够快速为贵公司带来新用户。</li><li><strong>案例：</strong> 去年我负责的一个项目，通过优化分享链路，仅用一个月就将获客成本降低了40%。</li><li><strong>重申：</strong> 因此，我有信心将这些成功经验复用到贵公司的业务增长中。</li></ul></li><li><p><strong>示例3：日常讨论（推荐一部电影）</strong></p><ul><li><strong>观点：</strong> 《奥本海默》绝对值得去电影院看IMAX版。</li><li><strong>理由：</strong> 因为它的音效设计和叙事节奏能给你带来极大的沉浸感。</li><li><strong>案例：</strong> 我看的那场，原子弹爆炸时的静默处理，让全场观众屏住呼吸了整整十秒，这种体验在家看电视是绝对感受不到的。</li><li><strong>重申：</strong> 所以，为了不浪费这部神作，一定要选最好的影厅去看。</li></ul></li></ul><h3 id="_2-scqa-汇报-说服" tabindex="-1">2. SCQA（汇报/说服） <a class="header-anchor" href="#_2-scqa-汇报-说服" aria-label="Permalink to &quot;2. SCQA（汇报/说服）&quot;">​</a></h3><p><strong>结构：情境 (Situation) -&gt; 冲突 (Complication) -&gt; 问题 (Question) -&gt; 答案 (Answer)</strong></p><ul><li><p><strong>示例1：项目启动汇报</strong></p><ul><li><strong>情境：</strong> 目前我们的客服团队有20人，主要处理用户的退换货咨询。</li><li><strong>冲突：</strong> 但随着大促来临，咨询量翻了5倍，现有人员即使24小时轮班，平均响应时间也已超过30分钟，导致投诉激增。</li><li><strong>问题：</strong> 在人力编制无法立刻翻倍的情况下，我们该如何保障服务质量？</li><li><strong>答案：</strong> 我建议引入AI智能客服系统，先处理70%的标准化高频问题，让人力集中在复杂投诉上。</li></ul></li><li><p><strong>示例2：向上级申请预算</strong></p><ul><li><strong>情境：</strong> 过去一年，我们部门的数据分析主要依靠手动Excel汇总。</li><li><strong>冲突：</strong> 现在数据源越来越多，手动处理不仅耗时两天，还经常出现公式错误，导致决策层拿到的数据往往是滞后的。</li><li><strong>问题：</strong> 我们如何在数据量暴增的同时，保证数据的实时性和准确性？</li><li><strong>答案：</strong> 建议采购一套BI商业智能工具，实现数据自动抓取和可视化，将报表产出时间从2天缩短至实时。</li></ul></li><li><p><strong>示例3：危机公关声明</strong></p><ul><li><strong>情境：</strong> 我们是致力于提供健康食品的“轻食主义”。</li><li><strong>冲突：</strong> 昨天有自媒体爆料称我们的沙拉中有异物，虽然经核查是供应商包装线偶发事件，但已引发大量用户恐慌。</li><li><strong>问题：</strong> 我们如何挽回品牌信誉并重建用户信任？</li><li><strong>答案：</strong> 我们将公开道歉，全额退款，并邀请第三方机构入驻工厂监督，同时推出“透明厨房”直播计划。</li></ul></li></ul><h3 id="_3-star-面试-复盘" tabindex="-1">3. STAR（面试/复盘） <a class="header-anchor" href="#_3-star-面试-复盘" aria-label="Permalink to &quot;3. STAR（面试/复盘）&quot;">​</a></h3><p><strong>结构：情境 (Situation) -&gt; 任务 (Task) -&gt; 行动 (Action) -&gt; 结果 (Result)</strong></p><ul><li><p><strong>示例1：面试（描述一次困难经历）</strong></p><ul><li><strong>情境：</strong> 去年双11，我司核心服务器突然宕机，官网瘫痪。</li><li><strong>任务：</strong> 作为运维负责人，我的任务是30分钟内恢复服务，并防止数据丢失。</li><li><strong>行动：</strong> 我立即启动了备用集群，同时协调开发团队限流降级非核心功能，并手动恢复了数据库日志。</li><li><strong>结果：</strong> 25分钟内恢复访问，数据零丢失，并将此次事故总结成预案，写入了SOP文档。</li></ul></li><li><p><strong>示例2：绩效面谈（个人贡献）</strong></p><ul><li><strong>情境：</strong> 上个季度，我们的App注册转化率一直卡在15%。</li><li><strong>任务：</strong> 领导指派我牵头优化注册流程，目标是提升至25%。</li><li><strong>行动：</strong> 我组织了用户调研，发现验证码接收慢是主因，于是我简化了流程，引入了第三方一键登录。</li><li><strong>结果：</strong> 注册转化率提升至28%，当季度新增有效用户5万人。</li></ul></li><li><p><strong>示例3：项目复盘（团队协作）</strong></p><ul><li><strong>情境：</strong> 某ToB客户对交付的系统非常不满，威胁终止合同。</li><li><strong>任务：</strong> 我被临时任命为救火队长，需要在两周内扭转客户印象。</li><li><strong>行动：</strong> 我每天驻场与客户开会，梳理出10个核心痛点，协调产研团队通宵定制开发补丁，并建立了专属服务群。</li><li><strong>结果：</strong> 客户满意度从30分回升至90分，成功续约并追加了二期订单。</li></ul></li></ul><h3 id="_4-fabe-销售-推销" tabindex="-1">4. FABE（销售/推销） <a class="header-anchor" href="#_4-fabe-销售-推销" aria-label="Permalink to &quot;4. FABE（销售/推销）&quot;">​</a></h3><p><strong>结构：特点 (Feature) -&gt; 优势 (Advantage) -&gt; 利益 (Benefit) -&gt; 证据 (Evidence)</strong></p><ul><li><p><strong>示例1：推销SaaS软件</strong></p><ul><li><strong>特点：</strong> 这款CRM系统支持“自动化工作流”。</li><li><strong>优势：</strong> 相比传统软件，它能自动根据客户行为触发邮件和任务提醒。</li><li><strong>利益：</strong> 这意味着销售员不用再花时间手动记录跟进，能把精力全放在谈单上，提高您的成单率。</li><li><strong>证据：</strong> 您可以看这张A公司的案例图，他们使用后销售人均产能提升了35%。</li></ul></li><li><p><strong>示例2：推销高端耳机</strong></p><ul><li><strong>特点：</strong> 这款耳机采用了最新的“空间音频”技术。</li><li><strong>优势：</strong> 它能模拟影院级的环绕声场，声音定位比普通耳机精准很多。</li><li><strong>利益：</strong> 您戴上它玩游戏或看电影时，会有身临其境的感觉，就像坐在电影院C位。</li><li><strong>证据：</strong> 这是知名科技媒体《XX评测》的打分，它在沉浸式体验这一项拿到了满分。</li></ul></li><li><p><strong>示例3：推销培训课程</strong></p><ul><li><strong>特点：</strong> 我们的课程提供“一对一导师陪跑”。</li><li><strong>优势：</strong> 不同于录播课，导师会根据你的作业进行逐字批改。</li><li><strong>利益：</strong> 这能帮您避开自学时的弯路，最快速度拿到跳槽涨薪的Offer。</li><li><strong>证据：</strong> 这是我们学员群里的最新捷报，这位同学学完后薪资涨了50%。</li></ul></li></ul><h3 id="_5-ride-谈判-博弈" tabindex="-1">5. RIDE（谈判/博弈） <a class="header-anchor" href="#_5-ride-谈判-博弈" aria-label="Permalink to &quot;5. RIDE（谈判/博弈）&quot;">​</a></h3><p><strong>结构：风险 (Risk) -&gt; 利益1 (Interest 1) -&gt; 缺点 (Drawback) -&gt; 利益2 (Interest 2)</strong></p><ul><li><p><strong>示例1：商务合作提案（说服甲方接受略高的报价）</strong></p><ul><li><strong>风险：</strong> 如果您选择市场上最低价的供应商，可能会面临售后响应慢甚至烂尾的风险。</li><li><strong>利益1：</strong> 选择我们，我们能保证7x24小时的专属技术支持，确保您的项目万无一失。</li><li><strong>缺点：</strong> 当然，坦白讲，我们的价格确实比市场均价高出10%。</li><li><strong>利益2：</strong> 但这10%换来的是核心系统的稳定性，为您避免的可能是一旦宕机导致的百万级损失，算下来性价比其实更高。</li></ul></li><li><p><strong>示例2：采购谈判（压价）</strong></p><ul><li><strong>风险：</strong> 如果我们继续维持现在的采购价，财务部可能会削减该品类的预算，导致明年我们无法与贵司续约。</li><li><strong>利益1：</strong> 如果我们能达成新的价格协议，我们可以签下为期3年的长期合同，保证贵司的基本盘。</li><li><strong>缺点：</strong> 我知道降价对你们利润有压力，这也是我们需要共同面对的挑战。</li><li><strong>利益2：</strong> 但是长期的稳定订单和规模效应，能帮助贵司摊薄固定成本，总体收益其实是上升的。</li></ul></li><li><p><strong>示例3：内部审批（申请增加HC/人头）</strong></p><ul><li><strong>风险：</strong> 如果不增加人手，现有的骨干员工会因为过劳而离职，导致核心业务停摆。</li><li><strong>利益1：</strong> 增加一个新人，能分担老员工的压力，保留团队的核心战斗力。</li><li><strong>缺点：</strong> 这确实会增加部门的薪资支出。</li><li><strong>利益2：</strong> 但新人的产出将覆盖其成本的3倍以上，而且能释放经理的时间去开拓新业务，这笔账是非常划算的。</li></ul></li></ul><h3 id="_6-aida-营销文案-激发行动" tabindex="-1">6. AIDA（营销文案/激发行动） <a class="header-anchor" href="#_6-aida-营销文案-激发行动" aria-label="Permalink to &quot;6. AIDA（营销文案/激发行动）&quot;">​</a></h3><p><strong>结构：注意 (Attention) -&gt; 兴趣 (Interest) -&gt; 欲望 (Desire) -&gt; 行动 (Action)</strong></p><ul><li><p><strong>示例1：朋友圈招生海报文案</strong></p><ul><li><strong>注意：</strong> “月薪3k的运营和月薪3w的运营，差在哪？”</li><li><strong>兴趣：</strong> 不是加班时长，而是你是否掌握了“数据驱动增长”的底层逻辑。</li><li><strong>欲望：</strong> 想象一下，当你能用数据精准预测爆款，老板对你刮目相看，升职加薪指日可待。</li><li><strong>行动：</strong> 扫码领取免费试听课，仅限前50名。</li></ul></li><li><p><strong>示例2：直播带货话术</strong></p><ul><li><strong>注意：</strong> “直播间所有的宝宝们，看过来！这款洗面奶是真正的‘毛孔吸尘器’！”</li><li><strong>兴趣：</strong> 它含有独有的活性炭微粒，能深入清洁平时洗不掉的油脂栓。</li><li><strong>欲望：</strong> 坚持用一周，你会发现黑头少了，鼻子摸起来像剥了壳的鸡蛋一样滑嫩。</li><li><strong>行动：</strong> 链接已上，拍一发二，库存只有200单，手慢无！</li></ul></li><li><p><strong>示例3：公益募捐广告</strong></p><ul><li><strong>注意：</strong> “这张照片里孩子的眼睛，已经三年没见过光明了。”</li><li><strong>兴趣：</strong> 他患了一种罕见的眼疾，只需要一个简单的手术就能重见蓝天。</li><li><strong>欲望：</strong> 只要2000元，你就能改变一个孩子的一生，让他看见妈妈的样子。</li><li><strong>行动：</strong> 请点击下方“我要捐款”，哪怕只捐一杯奶茶钱，也是一份希望。</li></ul></li></ul><h3 id="_7-电梯演讲-吸引投资-路演" tabindex="-1">7. 电梯演讲（吸引投资/路演） <a class="header-anchor" href="#_7-电梯演讲-吸引投资-路演" aria-label="Permalink to &quot;7. 电梯演讲（吸引投资/路演）&quot;">​</a></h3><p><strong>结构：共情 (Empathy) -&gt; 问题 (Problem) -&gt; 方案 (Solution) -&gt; 价值 (Value)</strong></p><ul><li><p><strong>示例1：创业路演（To VC）</strong></p><ul><li><strong>共情：</strong> “王总，您投过很多消费赛道，肯定知道现在获客成本有多高。”</li><li><strong>问题：</strong> “目前的电商模式下，商家每赚100块，可能得花40块去买流量，利润极薄。”</li><li><strong>方案：</strong> “我们做的‘私域拼团’模式，就是把买流量的钱返给用户，让用户自发裂变，不需要中心化流量采买。”</li><li><strong>价值：</strong> “目前我们已经验证了模型，ROI做到了1:5，希望能融500万，把这套模式复制到全国10个城市。”</li></ul></li><li><p><strong>示例2：跨部门争取资源</strong></p><ul><li><strong>共情：</strong> “李经理，我知道你们技术部最近排期特别满，大家都在赶进度。”</li><li><strong>问题：</strong> “但现在市场部有个痛点，每次做活动都要等开发排期改页面，错过了热点时机。”</li><li><strong>方案：</strong> “我想申请借调一位前端，专门为我们开发一套可视化的活动搭建工具。”</li><li><strong>价值：</strong> “这样以后市场部自己就能拖拽生成页面，不再占用你们核心开发的资源，还能让活动效率翻倍。”</li></ul></li><li><p><strong>示例3：求职自荐（To 面试官）</strong></p><ul><li><strong>共情：</strong> “张总，您一直在寻找能帮公司解决出海合规问题的人吧。”</li><li><strong>问题：</strong> “现在欧盟GDPR法规越来越严，很多同行因为数据合规问题被罚得血本无归。”</li><li><strong>方案：</strong> “我在前东家主导过全套GDPR合规改造，熟悉所有法律条文和技术落地细节。”</li><li><strong>价值：</strong> “加入贵司后，我能确保公司在欧洲市场的业务合法合规，规避千万级的罚款风险。”</li></ul></li></ul><p>如果你需要针对<strong>特定行业</strong>（如教育、金融、医疗）或<strong>具体场景</strong>（如年终述职、相亲介绍）来定制这些框架的话术，我可以帮你进一步细化。</p>',24)])])}const c=l(i,[["render",s]]);export{d as __pageData,c as default};
